@namespace Lumeo
@implements IAsyncDisposable
@inject IComponentInteropService Interop

@*
    SwipeActions — iOS Mail.app pattern. A horizontal "card" whose foreground
    slides on touch to reveal background action buttons on either side.

    Layout: three stacked layers inside a relatively-positioned root.
      1. Leading actions  — absolute, pinned to left edge, visible while
                            foreground slides right (deltaX > 0).
      2. Trailing actions — absolute, pinned to right edge, visible while
                            foreground slides left  (deltaX < 0).
      3. Foreground       — the consumer's ChildContent. Slides on pointer
                            events, can lock open at +/- OpenWidth.

    v1 simplification: the open distance is a constant (OpenWidth = 160px)
    rather than measuring the actions container width. Two 80px-wide buttons
    is the canonical iOS pattern. A v2 could read the rendered LeadingActions
    / TrailingActions width via getElementDimension and clamp dynamically.

    Clicking anywhere on the foreground while open closes the panel. Pointer
    events still arrive at action buttons because they sit BEHIND the
    foreground only while closed; once open, the foreground is translated
    aside and the actions become hit-testable normally.
*@

<div id="@_elementId"
     class="@CssClass"
     role="group"
     aria-label="@AriaLabel"
     @attributes="AdditionalAttributes">

    @if (LeadingActions is not null)
    {
        <div class="absolute inset-y-0 start-0 flex items-stretch"
             style="@($"width: {OpenWidthPx}px;")">
            @LeadingActions
        </div>
    }

    @if (TrailingActions is not null)
    {
        <div class="absolute inset-y-0 end-0 flex items-stretch justify-end"
             style="@($"width: {OpenWidthPx}px;")">
            @TrailingActions
        </div>
    }

    @* tabindex + keydown give keyboard users a way to reach the actions the
       gesture reveals: arrows open the matching side, Escape/Home close. Once
       open, the action buttons inside are reachable via Tab. *@
    <div id="@_foregroundId"
         class="relative z-10 bg-background focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-inset"
         style="@ForegroundStyle"
         tabindex="0"
         @onpointerdown="HandlePointerDown"
         @onpointermove="HandlePointerMove"
         @onpointerup="HandlePointerUp"
         @onpointercancel="HandlePointerUp"
         @onclick="HandleForegroundClick"
         @onkeydown="HandleKeyDown">
        @ChildContent
    </div>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public RenderFragment? LeadingActions { get; set; }
    [Parameter] public RenderFragment? TrailingActions { get; set; }
    [Parameter] public double ActivationThresholdPx { get; set; } = 80;
    /// <summary>Accessible label for the swipeable row, announced to AT users who can't see the gesture affordance.</summary>
    [Parameter] public string AriaLabel { get; set; } = "Swipeable item — use arrow keys to reveal actions";
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _elementId = LumeoIds.New("swa");
    private readonly string _foregroundId = LumeoIds.New("swa-fg");

    // v1: fixed open width — room for two 80px square action buttons.
    private const double OpenWidthPx = 160d;

    private long? _activePointerId;
    private double _startX;
    private double _startY;
    private double _currentOffset;     // current translateX of the foreground (px)
    private double _lockedOffset;      // 0 when closed, +OpenWidth (left open) or -OpenWidth (right open)
    private bool _dragging;
    // Track whether the gesture so far looks horizontal; if the user is
    // clearly scrolling vertically we abandon the swipe so we don't fight
    // the page's normal vertical scroll.
    private bool _gestureLocked;
    // Set true once a pointer gesture has actually moved the foreground, so the
    // synthesized click the browser fires after a mouse drag can be swallowed
    // (without this, a desktop swipe-open snaps shut immediately because the
    // trailing click runs HandleForegroundClick and resets the offset).
    private bool _didDrag;
    private bool _suppressNextClick;
    // True while we hold a pointer capture on the foreground (mid-drag), so we
    // know to release it on pointer-up / dispose even if the pointer drifted
    // off the element.
    private bool _hasPointerCapture;

    private string CssClass =>
        Cx.Merge("relative w-full overflow-hidden touch-pan-y select-none bg-background", Class);

    private string ForegroundStyle
    {
        get
        {
            var transition = _dragging
                ? "transition: none;"
                : "transition: transform 200ms ease-out;";
            var offset = _currentOffset.ToString("0.##", System.Globalization.CultureInfo.InvariantCulture);
            return $"transform: translateX({offset}px); {transition} will-change: transform;";
        }
    }

    private void HandlePointerDown(PointerEventArgs e)
    {
        if (_activePointerId.HasValue) return;
        // Clear any stale suppression flag from a prior gesture so it can never
        // survive into an unrelated later tap (touch never fires the synthetic
        // click that would otherwise consume it — see HandlePointerUp).
        _suppressNextClick = false;
        _activePointerId = e.PointerId;
        _startX = e.ClientX;
        _startY = e.ClientY;
        _dragging = true;
        _gestureLocked = false;
        _didDrag = false;
        // Begin from whatever side is locked open (if any) — allows the
        // user to "push" a locked panel back toward closed.
        _currentOffset = _lockedOffset;
    }

    private async Task HandlePointerMove(PointerEventArgs e)
    {
        if (!_activePointerId.HasValue || _activePointerId.Value != e.PointerId) return;

        var dx = e.ClientX - _startX;
        var dy = e.ClientY - _startY;

        // Direction lock: once the gesture commits to horizontal/vertical
        // we stick with it. If vertical, bail out entirely so the surrounding
        // list can scroll naturally.
        if (!_gestureLocked)
        {
            if (Math.Abs(dx) < 6 && Math.Abs(dy) < 6) return; // dead zone
            if (Math.Abs(dy) > Math.Abs(dx))
            {
                // Vertical — release control entirely.
                _activePointerId = null;
                _dragging = false;
                return;
            }
            _gestureLocked = true;
            _didDrag = true;
            // Capture the pointer once we commit to a horizontal drag so moves
            // keep routing here even if the pointer drifts off the foreground
            // (otherwise the card sticks half-open). Capture only after the
            // direction lock so we never steal vertical-scroll gestures.
            if (!_hasPointerCapture)
            {
                _hasPointerCapture = true;
                await Interop.SetPointerCaptureOnElement(_foregroundId, e.PointerId);
            }
        }

        var target = _lockedOffset + dx;
        // Clamp to the side that actually has actions; the other side stays at 0.
        var maxLeft = LeadingActions is not null ? OpenWidthPx : 0;
        var maxRight = TrailingActions is not null ? -OpenWidthPx : 0;
        if (target > maxLeft) target = maxLeft;
        if (target < maxRight) target = maxRight;

        _currentOffset = target;
        StateHasChanged();
    }

    private async Task HandlePointerUp(PointerEventArgs e)
    {
        if (!_activePointerId.HasValue || _activePointerId.Value != e.PointerId) return;

        var pointerId = _activePointerId.Value;
        _activePointerId = null;
        _dragging = false;

        if (_hasPointerCapture)
        {
            _hasPointerCapture = false;
            await Interop.ReleasePointerCaptureOnElement(_foregroundId, pointerId);
        }

        // A real drag just ended — swallow the click the browser synthesizes
        // next, so it doesn't immediately re-close the panel. Only MOUSE input
        // emits a trailing synthetic click; a touch drag does not, so gating on
        // pointer type keeps the flag from latching forever and swallowing the
        // first genuine close-tap after a touch swipe-open.
        if (_didDrag && e.PointerType == "mouse") _suppressNextClick = true;

        // Settle: if |offset| >= threshold, lock to that side's full open
        // position; otherwise spring back to 0.
        if (_currentOffset >= ActivationThresholdPx && LeadingActions is not null)
        {
            _lockedOffset = OpenWidthPx;
            _currentOffset = OpenWidthPx;
        }
        else if (_currentOffset <= -ActivationThresholdPx && TrailingActions is not null)
        {
            _lockedOffset = -OpenWidthPx;
            _currentOffset = -OpenWidthPx;
        }
        else
        {
            _lockedOffset = 0;
            _currentOffset = 0;
        }

        StateHasChanged();
    }

    private void HandleForegroundClick()
    {
        // Swallow the synthetic click that follows a mouse drag — otherwise the
        // panel we just opened would snap shut on the same gesture.
        if (_suppressNextClick)
        {
            _suppressNextClick = false;
            return;
        }

        // Tapping the foreground while open closes it. While closed this is
        // a no-op so consumers' own click handlers inside ChildContent still
        // work (clicks bubble down to children before this runs).
        if (_lockedOffset != 0)
        {
            _lockedOffset = 0;
            _currentOffset = 0;
            StateHasChanged();
        }
    }

    // Keyboard alternative to the swipe gesture (a11y): arrows open the side
    // that has actions, Escape / Home close. Once open, the action buttons
    // become reachable in the normal Tab order.
    private void HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "ArrowLeft":
                // Reveal trailing (right-edge) actions, mirroring a left swipe.
                if (TrailingActions is not null) OpenSide(-OpenWidthPx);
                break;
            case "ArrowRight":
                // Reveal leading (left-edge) actions, mirroring a right swipe.
                if (LeadingActions is not null) OpenSide(OpenWidthPx);
                break;
            case "Escape":
            case "Home":
                if (_lockedOffset != 0) OpenSide(0);
                break;
        }
    }

    private void OpenSide(double offset)
    {
        _lockedOffset = offset;
        _currentOffset = offset;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        // Release a still-held pointer capture if the component is torn down
        // mid-drag. The interop swallows JSDisconnectedException internally.
        if (_hasPointerCapture && _activePointerId.HasValue)
        {
            _hasPointerCapture = false;
            await Interop.ReleasePointerCaptureOnElement(_foregroundId, _activePointerId.Value);
        }
    }
}
